mapper.select:
/* DircMapper.selectWorkOrderList */ SELECT TOI.OPERTDRCT_ID , TOI.OPERT_DT , TOI.OPERTSTD_ID , TOI.OPERTSTD_PROCS_ID , TOI.ORDER_ID , TOI.CNNC_ID , TOI.BEGIN_TM , TOI.END_TM , TOPM.PRDUCT_ID , TOD.OPERTDRCT_DTL_ID , TOD.ORDER_DTL_ID , TOD.DSGN_ID , TPI.PRDUCT_NM , TPI.PRDUCT_M_CODE , TPI.PRDUCT_TY , TPII.IMG_ID , ICF.FILE_LINK_PATH , TBI.BRAND_ID , TCI.CLIENT_ID , TCI.CLIENT_NM , TOI2.OP_ID , TCI2.CMMN_NM FROM TB_OPERTDRCT_INFO TOI INNER JOIN TB_ORDER_PRDUCT_MAPNG TOPM ON TOI.ORDER_ID = TOPM.ORDER_ID INNER JOIN TB_OPERTDRCT_DETAIL TOD ON TOI.OPERTDRCT_ID = TOD.OPERTDRCT_ID AND TOI.OPERT_DT = TOD.OPERT_DT INNER JOIN TB_PRDUCT_INFO TPI ON TOPM.PRDUCT_ID = TPI.PRDUCT_ID LEFT JOIN TB_PRDUCT_IMG_INFO TPII ON TPI.PRDUCT_ID = TPII.PRDUCT_ID AND TPII.IMG_ID = '1' LEFT JOIN IFI_CMMN_FILE ICF ON TPII.FILE_SN = ICF.FILE_SN INNER JOIN TB_BRAND_INFO TBI ON TPI.BRAND_ID = TBI.BRAND_ID AND TPI.BPLC_ID = TBI.BPLC_ID INNER JOIN TB_CLIENT_INFO TCI ON TBI.CLIENT_ID = TCI.CLIENT_ID AND TBI.BPLC_ID = TCI.BPLC_ID INNER JOIN TB_EQPMN_OP_MAPNG TEOM ON TOI.CNNC_ID = TEOM.CNNC_ID INNER JOIN TB_OP_INFO TOI2 ON TEOM.OP_ID = TOI2.OP_ID INNER JOIN TB_CMMN_INFO TCI2 ON TCI2.CODE_SE = 'PRDT' AND TPI.PRDUCT_TY = TCI2.CMMN_CD AND TCI2.BPLC_ID = #{bplcId} AND TCI2.FCTRY_ID = #{fctryId} AND TBI.BPLC_ID = TCI2.BPLC_ID AND TCI.BPLC_ID = TCI2.BPLC_ID WHERE TOI.OPERT_DT = #{opertDt} AND TOI2.OP_ID = #{opId}
AND TCI.CLIENT_ID = #{clientId}
AND TPI.PRDUCT_TY = #{prductTy}
GROUP BY TOI.ORDER_ID, TOPM.PRDUCT_ID
